/**
 * DNS record content - varies by record type
 */
export type DnsRecordContent = {
    type: 'A';
    /**
     * A record - IPv4 address (as string, e.g., "192.0.2.1")
     */
    value: {
        address: string;
    };
} | {
    type: 'AAAA';
    /**
     * AAAA record - IPv6 address (as string, e.g., "2001:db8::1")
     */
    value: {
        address: string;
    };
} | {
    type: 'CNAME';
    /**
     * CNAME record - canonical name
     */
    value: {
        target: string;
    };
} | {
    type: 'TXT';
    /**
     * TXT record - text content
     */
    value: {
        content: string;
    };
} | {
    type: 'MX';
    /**
     * MX record - mail exchange
     */
    value: {
        priority: number;
        target: string;
    };
} | {
    type: 'NS';
    /**
     * NS record - nameserver
     */
    value: {
        nameserver: string;
    };
} | {
    type: 'SRV';
    /**
     * SRV record - service
     */
    value: {
        port: number;
        priority: number;
        target: string;
        weight: number;
    };
} | {
    type: 'CAA';
    /**
     * CAA record - certification authority authorization
     */
    value: {
        flags: number;
        tag: string;
        value: string;
    };
} | {
    type: 'PTR';
    /**
     * PTR record - pointer
     */
    value: {
        target: string;
    };
};

